mapper.sql:

  AND B.ORG_ID  = #{orgId}
  AND A.USER_ID = #{userId}
ORDER BY A.AUTHRT_ID

mapper.select:
	/*
		 SQL ID : UsrUserAuthGrpDAO.select
		 설  명 : 사용자의 권한 정보 조회
 	*/

	   AND A.USER_ID = #{userId}
	   AND A.USER_AUTHRT_ID = #{authGrpCd}
	   AND B.MENU_TYCD = #{menuType}

mapper.insert:
	/*
		 SQL ID : UsrUserAuthGrpDAO.insert
		 설  명 : 사용자의 권한 정보 등록
 	*/
 	INSERT INTO TB_LMS_USER_AUTHRT (
 		  MENU_TYCD
		, USER_AUTHRT_ID
		, USER_ID
		, ATFL_MAXSZ
		, RGTR_ID
		, FRST_INQ_DTTM
		, MDFR_ID
		, MOD_DTTM
 	) VALUES (
 		  #{menuType}
 		, #{authGrpCd}
 		, #{userId}
 		, #{fileLimitSize}
 		, #{rgtrId}
 		, FN_DTTM()
 		, #{mdfrId}
 		, FN_DTTM()
 	)

mapper.delete:
	/*
		 SQL ID : UsrUserAuthGrpDAO.delete
		 설  명 : 사용자의 권한 정보 삭제
 	*/
 	DELETE FROM TB_LMS_USER_AUTHRT
 	 WHERE USER_ID = #{userId}
 	   AND MENU_TYCD = #{menuType}
 	   AND USER_AUTHRT_ID = #{authGrpCd}

	/*
		 SQL ID : UsrUserAuthGrpDAO.deleteAll
		 설  명 : 사용자의 권한 정보 전체 삭제
 	*/
 	DELETE FROM TB_LMS_USER_AUTHRT
